module graycode_counter (
    input wire clk,
    input wire rst,
    output reg [2:0] gray_out
);

    reg [2:0] gray_code;

    always @(posedge clk or posedge rst) begin
        if (rst)
            gray_code <= 3'b000;
        else
            gray_code <= gray_code + 1;
    end

    always @(*) begin
        gray_out = gray_code ^ (gray_code >> 1);
    end

endmodule
